#nullable enable // autogenerated

using MVZ2Logic;
using MVZ2Logic.Definitions;
using MVZ2Logic.Options;
using MVZ2Logic.Saves;

namespace MVZ2.GameContent.Options
{
    [AutoOptionWidgetDefinition(LogicOptionWidgetNames.particleAmount)]
    public class ParticleAmountOptionSlider : OptionSliderDefinition
    {
        public ParticleAmountOptionSlider(string nsp, string name) : base(nsp, name)
        {
        }
        public override float GetValue(IOptionContext context)
        {
            return Global.Options.GetParticleAmount();
        }
        public override string GetLabelValue(IOptionContext context, float value)
        {
            return LogicMain.GetFloatPercentageText(value);
        }
        public override void OnValueChanged(IOptionContext context, float value)
        {
            Global.Options.SetParticleAmount(value);
        }

        public override void OnEndEdit(IOptionContext context, float value)
        {
            Global.Options.SetParticleAmount(value);
            Global.Options.SaveOptions();
        }
    }
}
